import re
def norm_doc(d):
    return re.sub(r"[^a-z0-9]", "", d.casefold())
def block_key(r):
    ap = r["name"].casefold().strip().split()[-1]
    return f"{ap}|{r['region'].casefold()}"
def er_score(a, b):
    if norm_doc(a["document_id"]) == norm_doc(b["document_id"]) and block_key(a) == block_key(b):
        return 1.0
    if block_key(a) == block_key(b):
        return 0.5
    return 0.0
a = {"name": "Ana Quispe", "document_id": "D-12.34", "region": "Lima"}
b = {"name": "ANA QUISPE", "document_id": "d1234", "region": "Lima"}
c = {"name": "Ana Quispe", "document_id": "Z9", "region": "Lima"}
d = {"name": "Luis Rojas", "document_id": "Z9", "region": "Cusco"}
print(er_score(a, b), er_score(a, c), er_score(a, d))

def shared_email(a, b):
    return bool(a.get("email") and a.get("email") == b.get("email"))
print(shared_email({"email": "a@x.com"}, {"email": "a@x.com"}))
print(shared_email({"email": "a@x.com"}, {"email": "b@x.com"}))
print(shared_email({"email": None}, {"email": "a@x.com"}))

def rel_score(km, surname_jaccard):
    geo = 1.0 if km <= 2 else 0.0
    return round(0.5 * geo + 0.5 * surname_jaccard, 1)
print(rel_score(1.2, 1.0), rel_score(5.0, 0.4))

txs = [("A","D",1), ("C","D",1), ("A","E",1), ("C","F",1)]
def neighbors(txs, node):
    s = set()
    for x, y, _ in txs:
        if x == node:
            s.add(y)
        if y == node:
            s.add(x)
    return s
print(sorted(neighbors(txs, "A") & neighbors(txs, "C")))

def uncertainty_band(missing, conflict):
    if conflict or len(missing) >= 2:
        return "high"
    if missing:
        return "med"
    return "low"
print(uncertainty_band([], False), uncertainty_band(["e"], False),
      uncertainty_band(["e","p"], False), uncertainty_band([], True))

